# -----------------------------------------------------------------------------
# Register a named validation pattern from configuration
# -----------------------------------------------------------------------------
sub register_pattern {
    my ($self, $name, $raw_pattern, $raw_modifiers, $description) = @_;

    croak "Pattern name is required" unless defined $name && length $name;
    croak "Pattern name must be alphanumeric" unless $name =~ /\A[a-zA-Z_][a-zA-Z0-9_]*\z/;

    my $compiled = $self->compile_pattern($raw_pattern, $raw_modifiers);

    $self->{patterns}{$name} = {
        compiled    => $compiled,
        source      => $raw_pattern,
        modifiers   => $self->sanitize_modifiers($raw_modifiers),
        description => $description || '',
    };

    return 1;
}

# -----------------------------------------------------------------------------
# Load patterns from a configuration hash
# Expected format: { name => { pattern => '...', modifiers => '...', description => '...' } }
# -----------------------------------------------------------------------------
sub load_config {
    my ($self, $config) = @_;

    croak "Configuration must be a hash reference" unless ref $config eq 'HASH';

    my @loaded;
    my @failed;

    for my $name (sort keys %$config) {
        my $entry = $config->{$name};
        eval {
            $self->register_pattern(
                $name,
                $entry->{pattern},
                $entry->{modifiers} || '',
                $entry->{description} || '',
            );
            push @loaded, $name;
        };
        if ($@) {
            push @failed, { name => $name, error => $@ };
            $self->{log_callback}->("Failed to load pattern '$name': $@");
        }
    }

    return { loaded => \@loaded, failed => \@failed };
}

